#[derive(Clone)]
pub struct StackValue {
    // C: StackValue.val — the payload TValue
    pub val: LuaValue,
    // C: StackValue.tbclist.delta — to-be-closed linked-list delta
    pub tbc_delta: u16,
}

impl Default for StackValue {
